132	function loadScopedCapabilityRuntimeRegistryEntries<T>(params: {
133	  pluginId: string;
134	  capabilityLabel: string;
135	  loadEntries: (registry: BundledCapabilityRuntimeRegistry) => T[];
136	  loadDeclaredIds: (
137	    plugin: BundledCapabilityRuntimeRegistry["plugins"][number],
138	  ) => readonly string[];
139	}): T[] {
140	  let lastFailure: Error | undefined;
141	
142	  for (let attempt = 0; attempt < 2; attempt += 1) {
143	    const registry = loadBundledCapabilityRuntimeRegistry({
144	      pluginIds: [params.pluginId],
145	      pluginSdkResolution: "dist",
146	    });
147	    const entries = params.loadEntries(registry);
148	    if (entries.length > 0) {
149	      return entries;
150	    }
151	
152	    const plugin = registry.plugins.find((entry) => entry.id === params.pluginId);
153	    lastFailure = formatBundledCapabilityPluginLoadError({
154	      pluginId: params.pluginId,
155	      capabilityLabel: params.capabilityLabel,
156	      registry,
157	    });
158	    const shouldRetry =
159	      attempt === 0 &&
160	      (!plugin || plugin.status !== "loaded" || params.loadDeclaredIds(plugin).length === 0);
161	    if (!shouldRetry) {
162	      break;
163	    }
164	  }
165	
166	  throw (
167	    lastFailure ??
168	    new Error(
169	      `bundled ${params.capabilityLabel} contract load failed for ${params.pluginId}: no entries`,
170	    )
171	  );
172	}
