416	export function getPackageManifestMetadata(
417	  manifest: PackageManifest | undefined,
418	): OpenClawPackageManifest | undefined {
419	  if (!manifest) {
420	    return undefined;
421	  }
422	  return manifest[MANIFEST_KEY];
