425	export function resolvePackageExtensionEntries(
426	  manifest: PackageManifest | undefined,
427	): PackageExtensionResolution {
428	  const raw = getPackageManifestMetadata(manifest)?.extensions;
429	  if (!Array.isArray(raw)) {
430	    return { status: "missing", entries: [] };
431	  }
432	  const entries = raw
433	    .map((entry) => (typeof entry === "string" ? entry.trim() : ""))
434	    .filter(Boolean);
435	  if (entries.length === 0) {
436	    return { status: "empty", entries: [] };
437	  }
438	  return { status: "ok", entries };
439	}
