61	function isNostrSenderAllowed(senderPubkey: string, allowFrom: string[]): boolean {
62	  const normalizedSender = normalizePubkey(senderPubkey);
63	  for (const entry of allowFrom) {
64	    const normalized = normalizeNostrAllowEntry(entry);
65	    if (normalized === "*") {
66	      return true;
67	    }
68	    if (normalized === normalizedSender) {
69	      return true;
70	    }
71	  }
72	  return false;
73	}
