  const resolvedAccess = await resolveNostrDirectAccess({
    cfg, accountId, dmPolicy, allowFrom, senderPubkey, rawBody: text, runtime
  });
  if (resolvedAccess.access.decision !== "allow") {
    return;
  }
  await dispatchInboundDirectDmWithRuntime({
