118	    }
119	    return null;
120	  },
121	  applyAccountConfig: ({ cfg, input }) => {
122	    const typedInput = input as {
123	      useEnv?: boolean;
124	      privateKey?: string;
125	      relayUrls?: string;
126	    };
127	    const relayResult = typedInput.relayUrls?.trim()
128	      ? parseRelayUrls(typedInput.relayUrls)
129	      : { relays: [] };
130	    return patchTopLevelChannelConfigSection({
131	      cfg,
132	      channel,
133	      enabled: true,
134	      clearFields: typedInput.useEnv ? ["privateKey"] : undefined,
135	      patch: {
136	        ...(typedInput.useEnv ? {} : { privateKey: typedInput.privateKey?.trim() }),
137	        ...(relayResult.relays.length > 0 ? { relays: relayResult.relays } : {}),
138	      },
139	    });
140	  },
141	};
