146	  resolveShouldPromptAccountIds: () => false,
147	  status: createStandardChannelSetupStatus({
148	    channelLabel: "Nostr",
149	    configuredLabel: "configured",
150	    unconfiguredLabel: "needs private key",
151	    configuredHint: "configured",
152	    unconfiguredHint: "needs private key",
153	    configuredScore: 1,
154	    unconfiguredScore: 0,
