import {
  DEFAULT_ACCOUNT_ID,
  normalizeAccountId,
  normalizeOptionalAccountId,
} from "openclaw/plugin-sdk/account-id";
import {
  listCombinedAccountIds,
  resolveListedDefaultAccountId,
} from "openclaw/plugin-sdk/account-resolution";
import { normalizeSecretInputString, type SecretInput } from "openclaw/plugin-sdk/secret-input";
import type { OpenClawConfig } from "../api.js";

export interface PulseBoardAccountConfig {
  enabled?: boolean;
  name?: string;
  defaultAccount?: string;
  apiToken?: SecretInput;
  serverUrl?: string;
  username?: string;
  boards?: string[];
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom?: Array<string | number>;
}

export interface ResolvedPulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  apiToken: string;
  serverUrl: string;
  username: string;
  boards: string[];
  config: PulseBoardAccountConfig;
}

function resolveConfiguredDefaultPulseBoardAccountId(cfg: OpenClawConfig): string | undefined {
  const pbCfg = (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;
  return normalizeOptionalAccountId(pbCfg?.defaultAccount);
}

/**
 * List all configured PulseBoard account IDs.
 * Returns a single implicit account when apiToken, serverUrl, and username are all set.
 */
export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;
  const apiToken = normalizeSecretInputString(pbCfg?.apiToken);
  const serverUrl = pbCfg?.serverUrl?.trim();
  const username = pbCfg?.username?.trim();
  const isConfigured = Boolean(apiToken && serverUrl && username);
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId: isConfigured
      ? (resolveConfiguredDefaultPulseBoardAccountId(cfg) ?? DEFAULT_ACCOUNT_ID)
      : undefined,
  });
}

/**
 * Get the default PulseBoard account ID.
 */
export function resolveDefaultPulseBoardAccountId(cfg: OpenClawConfig): string {
  return resolveListedDefaultAccountId({
    accountIds: listPulseBoardAccountIds(cfg),
    configuredDefaultAccountId: resolveConfiguredDefaultPulseBoardAccountId(cfg),
  });
}

/**
 * Resolve a PulseBoard account from config.
 */
export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(
    opts.accountId ?? resolveDefaultPulseBoardAccountId(opts.cfg),
  );
  const pbCfg = (opts.cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;

  const enabled = pbCfg?.enabled !== false;
  const apiToken = normalizeSecretInputString(pbCfg?.apiToken) ?? "";
  const serverUrl = pbCfg?.serverUrl?.trim() ?? "";
  const username = pbCfg?.username?.trim() ?? "";
  const configured = Boolean(apiToken && serverUrl && username);

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled,
    configured,
    apiToken,
    serverUrl,
    username,
    boards: pbCfg?.boards ?? [],
    config: {
      enabled: pbCfg?.enabled,
      name: pbCfg?.name,
      defaultAccount: pbCfg?.defaultAccount,
      apiToken: pbCfg?.apiToken,
      serverUrl: pbCfg?.serverUrl,
      username: pbCfg?.username,
      boards: pbCfg?.boards,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
    },
  };
}

