import {
  AllowFromListSchema,
  buildChannelConfigSchema,
  DmPolicySchema,
  MarkdownConfigSchema,
} from "openclaw/plugin-sdk/channel-config-primitives";
import { buildSecretInputSchema } from "openclaw/plugin-sdk/secret-input";
import { z } from "openclaw/plugin-sdk/zod";

/**
 * Validates ws:// or wss:// URLs only.
 */
const webSocketUrlSchema = z
  .string()
  .refine(
    (url) => {
      try {
        const parsed = new URL(url);
        return parsed.protocol === "ws:" || parsed.protocol === "wss:";
      } catch {
        return false;
      }
    },
    { message: "serverUrl must use ws:// or wss:// protocol" },
  );

/**
 * Zod schema for channels.pulseboard.* configuration
 */
export const PulseBoardConfigSchema = z.object({
  /** Account display name */
  name: z.string().optional(),

  /** Optional default account id for routing/account selection */
  defaultAccount: z.string().optional(),

  /** Whether this channel is enabled */
  enabled: z.boolean().optional(),

  /** Markdown formatting overrides (tables) */
  markdown: MarkdownConfigSchema,

  /** PulseBoard API token for authentication */
  apiToken: buildSecretInputSchema().optional(),

  /** PulseBoard server WebSocket URL (wss://...) */
  serverUrl: webSocketUrlSchema.optional(),

  /** Your username on the PulseBoard server */
  username: z.string().optional(),

  /** Boards to subscribe to (e.g., ["#general", "#dev"]) */
  boards: z
    .array(
      z.string().refine((b) => b.startsWith("#"), { message: "Board names must start with #" }),
    )
    .optional(),

  /** DM access policy: pairing, allowlist, open, or disabled */
  dmPolicy: DmPolicySchema.optional(),

  /** Allowed sender usernames */
  allowFrom: AllowFromListSchema,
});

export type PulseBoardConfig = z.infer<typeof PulseBoardConfigSchema>;

/** JSON Schema for Control UI (converted from Zod) */
export const pulseBoardChannelConfigSchema = buildChannelConfigSchema(PulseBoardConfigSchema);

