/**
 * PulseBoard client interface and stub factory.
 *
 * PulseBoard is a fictional real-time bulletin board platform. This module
 * defines the typed interface for the connection layer. A real deployment
 * would open a WebSocket to opts.serverUrl, authenticate with opts.apiToken,
 * subscribe to the requested boards, and route inbound frames to the
 * onMessage callback.
 */

/** An inbound message received from the PulseBoard server. */
export interface PulseBoardInboundMessage {
  /** Unique message ID assigned by the server */
  messageId: string;
  /** "dm" for a direct message, "board" for a board post */
  type: "dm" | "board";
  /** Username of the sender */
  from: string;
  /** Target: "@myusername" for DMs, "#boardname" for board posts */
  target: string;
  /** Message text content */
  text: string;
  /** Unix epoch milliseconds */
  timestamp: number;
}

export interface PulseBoardClientOptions {
  /** WebSocket server URL (ws:// or wss://) */
  serverUrl: string;
  /** Your username on PulseBoard */
  username: string;
  /** API token for authentication */
  apiToken: string;
  /** Board names to subscribe to (must start with "#") */
  boards?: string[];
  /** Called for every inbound message (DM or board post) */
  onMessage: (msg: PulseBoardInboundMessage) => Promise<void>;
  /** Called when the connection is established */
  onConnect?: () => void;
  /** Called when the connection is closed */
  onDisconnect?: () => void;
  /** Called on connection errors */
  onError?: (err: Error) => void;
}

/** Live connection handle returned by startPulseBoardClient. */
export interface PulseBoardClient {
  /** Send a direct message to another user. */
  sendDm(username: string, text: string): Promise<{ messageId: string }>;
  /** Post a message to a named board (e.g., "#general"). */
  sendBoard(board: string, text: string): Promise<{ messageId: string }>;
  /** Close the connection and free resources. */
  close(): void;
}

let _idCounter = 0;

function generateMessageId(): string {
  _idCounter += 1;
  return `pb-${Date.now()}-${_idCounter}`;
}

/**
 * Start a PulseBoard client connection.
 *
 * The stub implementation resolves immediately (simulating a successful
 * connection handshake) and returns a client whose send methods produce
 * synthetic message IDs. Replace the body of this function with a real
 * WebSocket implementation for production use.
 */
export async function startPulseBoardClient(
  opts: PulseBoardClientOptions,
): Promise<PulseBoardClient> {
  // A real implementation would:
  //   const ws = new WebSocket(opts.serverUrl);
  //   ws.addEventListener("open", () => {
  //     authenticate(ws, opts.apiToken);
  //     for (const board of opts.boards ?? []) subscribeBoard(ws, board);
  //     opts.onConnect?.();
  //   });
  //   ws.addEventListener("message", (event) => {
  //     const msg = parseFrame(event.data);
  //     opts.onMessage(msg);
  //   });
  //   ws.addEventListener("close", () => opts.onDisconnect?.());
  //   ws.addEventListener("error", (e) => opts.onError?.(new Error(String(e))));

  // Notify the caller that the connection is "established".
  opts.onConnect?.();

  let closed = false;

  return {
    async sendDm(username: string, _text: string): Promise<{ messageId: string }> {
      if (closed) {
        throw new Error(`PulseBoard client is closed (account: ${opts.username})`);
      }
      // Real: send a WS frame { type: "dm", to: username, text }.
      void username;
      return { messageId: generateMessageId() };
    },

    async sendBoard(board: string, _text: string): Promise<{ messageId: string }> {
      if (closed) {
        throw new Error(`PulseBoard client is closed (account: ${opts.username})`);
      }
      // Real: send a WS frame { type: "board", board, text }.
      void board;
      return { messageId: generateMessageId() };
    },

    close(): void {
      if (!closed) {
        closed = true;
        opts.onDisconnect?.();
      }
    },
  };
}

