  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  if (trimmed.startsWith("#")) {
    // Board name: must have at least one character after "#"
    const board = trimmed.slice(1).trim();
    return board ? `#${board}` : undefined;
  }
  // Direct message: strip leading "@" if present
  const username = trimmed.startsWith("@") ? trimmed.slice(1).trim() : trimmed;
  return username || undefined;
}

/**
 * Returns true if the input looks like a valid PulseBoard target ID.
 *
 * Accepts:
 *   - Board names:  "#general", "#dev-chat"
 *   - Usernames:    "alice", "@alice", "user_123"
 */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  // Board: "#" followed by word/dash characters
  if (trimmed.startsWith("#")) {
    return /^#[\w-]+$/.test(trimmed);
  }
  // Username: optional "@" followed by word/dash characters
  const username = trimmed.startsWith("@") ? trimmed.slice(1) : trimmed;
  return /^[\w-]+$/.test(username) && username.length > 0;
}

/**
 * Normalize a PulseBoard allowFrom entry (a username).
 * Strips the leading "@" and surrounding whitespace.
 * Returns "*" for the wildcard, null for empty/invalid entries.
 */
export function normalizePulseBoardAllowEntry(entry: string): string | "*" | null {
  const trimmed = entry.trim();
  if (!trimmed) {
    return null;
  }
  if (trimmed === "*") {
    return "*";
  }
  const username = trimmed.startsWith("@") ? trimmed.slice(1).trim() : trimmed;
  return username || null;
}

/**
 * Returns true if the sender is present in the allowFrom list.
 * Comparison is case-insensitive.
 */
export function isPulseBoardSenderAllowed(
  senderUsername: string,
  allowFrom: string[],
): boolean {
  const normalizedSender = senderUsername.toLowerCase().trim();
  for (const entry of allowFrom) {
    const normalized = normalizePulseBoardAllowEntry(entry);
    if (normalized === "*") {
      return true;
    }
    if (normalized?.toLowerCase() === normalizedSender) {
      return true;
    }
  }
  return false;
}

