import {
  buildChannelOutboundSessionRoute,
  stripChannelTargetPrefix,
  type ChannelOutboundSessionRouteParams,
} from "openclaw/plugin-sdk/core";
import { isBoardTarget } from "./normalize.js";

/**
 * Resolve an outbound session route for a PulseBoard target.
 *
 * - Board targets ("#general") → group peer, chatType "group"
 * - User targets ("alice")     → direct peer, chatType "direct"
 */
export function resolvePulseBoardOutboundSessionRoute(
  params: ChannelOutboundSessionRouteParams,
) {
  const target = stripChannelTargetPrefix(params.target, "pulseboard");
  if (!target) {
    return null;
  }

  if (isBoardTarget(target)) {
    return buildChannelOutboundSessionRoute({
      cfg: params.cfg,
      agentId: params.agentId,
      channel: "pulseboard",
      accountId: params.accountId,
      peer: {
        kind: "group",
        id: target,
      },
      chatType: "group",
      from: `pulseboard:${target}`,
      to: `pulseboard:${target}`,
    });
  }

  return buildChannelOutboundSessionRoute({
    cfg: params.cfg,
    agentId: params.agentId,
    channel: "pulseboard",
    accountId: params.accountId,
    peer: {
      kind: "direct",
      id: target,
    },
    chatType: "direct",
    from: `pulseboard:${target}`,
    to: `pulseboard:${target}`,
  });
}

