import type { ChannelSetupAdapter } from "openclaw/plugin-sdk/channel-setup";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import {
  hasConfiguredSecretInput,
  normalizeSecretInputString,
} from "openclaw/plugin-sdk/secret-input";
import type { ChannelSetupDmPolicy, ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import {
  createStandardChannelSetupStatus,
  createTopLevelChannelDmPolicy,
  createTopLevelChannelParsedAllowFromPrompt,
  formatDocsLink,
  mergeAllowFromEntries,
  parseSetupEntriesWithParser,
  patchTopLevelChannelConfigSection,
  splitSetupEntries,
} from "openclaw/plugin-sdk/setup";
import { normalizePulseBoardAllowEntry } from "./normalize.js";
import type { PulseBoardAccountConfig } from "./types.js";
import { resolvePulseBoardAccount } from "./types.js";

const channel = "pulseboard" as const;

const PULSEBOARD_SETUP_HELP_LINES = [
  "You will need a PulseBoard API token, server URL, and your username.",
  "Server URL must be a WebSocket URL (ws:// or wss://).",
  "Env var supported: PULSEBOARD_API_TOKEN (default account only).",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

const PULSEBOARD_ALLOW_FROM_HELP_LINES = [
  "Allowlist PulseBoard DMs by username.",
  "Examples:",
  "- alice",
  "- @bob",
  "Multiple entries: comma-separated.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

function parseServerUrl(value: string): string | undefined {
  if (!value.trim()) return undefined;
  try {
    const parsed = new URL(value.trim());
    if (parsed.protocol !== "ws:" && parsed.protocol !== "wss:") {
      return "Server URL must use ws:// or wss:// protocol.";
    }
    return undefined;
  } catch {
    return `Invalid server URL: ${value}`;
  }
}

function parseBoardNames(raw: string): { boards: string[]; error?: string } {
  const entries = splitSetupEntries(raw);
  const boards: string[] = [];
  for (const entry of entries) {
    const normalized = entry.startsWith("#") ? entry : `#${entry}`;
    if (!/^#[\w-]+$/.test(normalized)) {
      return { boards: [], error: `Invalid board name: ${entry}` };
    }
    boards.push(normalized);
  }
  return { boards: [...new Set(boards)] };
}

function parsePulseBoardAllowFrom(raw: string): { entries: string[]; error?: string } {
  return parseSetupEntriesWithParser(raw, (entry) => {
    const normalized = normalizePulseBoardAllowEntry(entry);
    if (!normalized) {
      return { error: `Invalid PulseBoard username: ${entry}` };
    }
    return { value: normalized };
  });
}

const promptPulseBoardAllowFrom = createTopLevelChannelParsedAllowFromPrompt({
  channel,
  defaultAccountId: DEFAULT_ACCOUNT_ID,
  noteTitle: "PulseBoard DM allowlist",
  noteLines: PULSEBOARD_ALLOW_FROM_HELP_LINES,
  message: "PulseBoard allowFrom",
  placeholder: "alice, @bob",
  parseEntries: parsePulseBoardAllowFrom,
  mergeEntries: ({ existing, parsed }) => mergeAllowFromEntries(existing, parsed),
});

const pulseBoardDmPolicy: ChannelSetupDmPolicy = createTopLevelChannelDmPolicy({
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => {
    const pbCfg = (cfg.channels as Record<string, unknown> | undefined)
      ?.pulseboard as PulseBoardAccountConfig | undefined;
    return pbCfg?.dmPolicy ?? "pairing";
  },
  promptAllowFrom: promptPulseBoardAllowFrom,
});

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: () => DEFAULT_ACCOUNT_ID,
  applyAccountName: ({ cfg, name }) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: name?.trim() ? { name: name.trim() } : {},
    }),
  validateInput: ({ input }) => {
    const typedInput = input as {
      useEnv?: boolean;
      apiToken?: string;
      serverUrl?: string;
      username?: string;
    };
    if (!typedInput.useEnv && !typedInput.apiToken?.trim()) {
      return "PulseBoard requires --api-token or --use-env.";
    }
    const serverUrlError = parseServerUrl(typedInput.serverUrl ?? "");
    if (typedInput.serverUrl && serverUrlError) {
      return serverUrlError;
    }
    if (!typedInput.serverUrl?.trim()) {
      return "PulseBoard requires a server URL (ws:// or wss://).";
    }
    if (!typedInput.username?.trim()) {
      return "PulseBoard requires a username.";
    }
    return null;
  },
  applyAccountConfig: ({ cfg, input }) => {
    const typedInput = input as {
      useEnv?: boolean;
      apiToken?: string;
      serverUrl?: string;
      username?: string;
      boards?: string;
    };
    const boardResult = typedInput.boards?.trim()
      ? parseBoardNames(typedInput.boards)
      : { boards: [] };
    return patchTopLevelChannelConfigSection({
      cfg,
      channel,
      enabled: true,
      clearFields: typedInput.useEnv ? ["apiToken"] : undefined,
      patch: {
        ...(typedInput.useEnv ? {} : { apiToken: typedInput.apiToken?.trim() }),
        serverUrl: typedInput.serverUrl?.trim(),
        username: typedInput.username?.trim(),
        ...(boardResult.boards.length > 0 ? { boards: boardResult.boards } : {}),
      },
    });
  },
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  resolveAccountIdForConfigure: () => DEFAULT_ACCOUNT_ID,
  resolveShouldPromptAccountIds: () => false,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API token, server URL, and username",
    configuredHint: "configured",
    unconfiguredHint: "needs API token, server URL, and username",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) => resolvePulseBoardAccount({ cfg }).configured,
    resolveExtraStatusLines: ({ cfg }) => {
      const account = resolvePulseBoardAccount({ cfg });
      const lines: string[] = [];
      if (account.serverUrl) {
        lines.push(`Server: ${account.serverUrl}`);
      }
      if (account.username) {
        lines.push(`Username: ${account.username}`);
      }
      if (account.boards.length > 0) {
        lines.push(`Boards: ${account.boards.join(", ")}`);
      }
      return lines;
    },
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: PULSEBOARD_SETUP_HELP_LINES,
  },
  envShortcut: {
    prompt: "PULSEBOARD_API_TOKEN detected. Use env var?",
    preferredEnvVar: "PULSEBOARD_API_TOKEN",
    isAvailable: ({ cfg, accountId }) =>
      accountId === DEFAULT_ACCOUNT_ID &&
      Boolean(process.env.PULSEBOARD_API_TOKEN?.trim()) &&
      !hasConfiguredSecretInput(resolvePulseBoardAccount({ cfg, accountId }).config.apiToken),
    apply: async ({ cfg }) =>
      patchTopLevelChannelConfigSection({
        cfg,
        channel,
        enabled: true,
        clearFields: ["apiToken"],
        patch: {},
      }),
  },
  credentials: [
    {
      inputKey: "apiToken",
      providerHint: channel,
      credentialLabel: "API token",
      preferredEnvVar: "PULSEBOARD_API_TOKEN",
      helpTitle: "PulseBoard API token",
      helpLines: PULSEBOARD_SETUP_HELP_LINES,
      envPrompt: "PULSEBOARD_API_TOKEN detected. Use env var?",
      keepPrompt: "PulseBoard API token already configured. Keep it?",
      inputPrompt: "PulseBoard API token",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return {
          accountConfigured: account.configured,
          hasConfiguredValue: hasConfiguredSecretInput(account.config.apiToken),
          resolvedValue: normalizeSecretInputString(account.config.apiToken),
          envValue: process.env.PULSEBOARD_API_TOKEN?.trim(),
        };
      },
      applyUseEnv: async ({ cfg }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: ["apiToken"],
          patch: {},
        }),
      applySet: async ({ cfg, resolvedValue }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { apiToken: resolvedValue },
        }),
    },
  ],
  textInputs: [
    {
      inputKey: "serverUrl",
      message: "PulseBoard server URL (ws:// or wss://)",
      placeholder: "wss://pulseboard.example.com",
      required: true,
      helpTitle: "PulseBoard server URL",
      helpLines: [
        "The WebSocket URL of your PulseBoard server.",
        "Use wss:// for secure connections (recommended).",
      ],
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg, accountId }).serverUrl,
      keepPrompt: (value) => `Server URL set (${value}). Keep it?`,
      validate: ({ value }) => parseServerUrl(value),
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { serverUrl: value.trim() },
        }),
    },
    {
      inputKey: "username",
      message: "Your PulseBoard username",
      placeholder: "alice",
      required: true,
      helpTitle: "PulseBoard username",
      helpLines: ["Your account username on the PulseBoard server."],
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg, accountId }).username,
      keepPrompt: (value) => `Username set (${value}). Keep it?`,
      validate: ({ value }) => (value.trim() ? undefined : "Username is required."),
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { username: value.trim() },
        }),
    },
    {
      inputKey: "boards",
      message: "Boards to subscribe to (comma-separated, optional)",
      placeholder: "#general, #dev",
      required: false,
      applyEmptyValue: true,
      helpTitle: "PulseBoard boards",
      helpLines: [
        "Board names to subscribe to for group messages.",
        "Prefix with # (e.g., #general). Leave blank for DMs only.",
      ],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return account.boards.join(", ");
      },
      keepPrompt: (value) => `Boards set (${value}). Keep them?`,
      validate: ({ value }) => (value.trim() ? parseBoardNames(value).error : undefined),
      applySet: async ({ cfg, value }) => {
        const boardResult = value.trim() ? parseBoardNames(value) : { boards: [] };
        return patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: boardResult.boards.length === 0 ? ["boards"] : undefined,
          patch: boardResult.boards.length > 0 ? { boards: boardResult.boards } : {},
        });
      },
    },
  ],
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: { enabled: false },
    }),
};

