            boards: account.boards,

            onMessage: async (msg) => {
              // Ignore messages sent by this account itself.
              if (msg.from === account.username) {
                return;
              }

              if (msg.type === "dm") {
                const resolvedAccess = await resolveInboundAccess(msg.from, msg.text);

                if (resolvedAccess.access.decision === "pairing") {
                  // New sender — issue a pairing challenge via DM.
                  await pairing.issueChallenge({
                    senderId: msg.from,
                    senderIdLine: `Your PulseBoard username: ${msg.from}`,
                    sendPairingReply: async (text) => {
                      await clientHandle?.sendDm(msg.from, text);
                    },
                    onCreated: () => {
                      ctx.log?.debug?.(
                        `[${account.accountId}] pulseboard pairing request sender=${msg.from}`,
                      );
                    },
                    onReplyError: (err) => {
                      ctx.log?.warn?.(
                        `[${account.accountId}] pulseboard pairing reply failed for ${msg.from}: ${String(err)}`,
                      );
                    },
                  });
                  return;
                }

                if (resolvedAccess.access.decision !== "allow") {
                  ctx.log?.debug?.(
                    `[${account.accountId}] dropping PulseBoard DM from ${msg.from} (${resolvedAccess.access.reason})`,
                  );
                  return;
                }

                await dispatchInboundDirectDmWithRuntime({
                  cfg: ctx.cfg,
                  runtime,
                  channel: "pulseboard",
                  channelLabel: "PulseBoard",
                  accountId: account.accountId,
                  peer: { kind: "direct", id: msg.from },
                  senderId: msg.from,
                  senderAddress: `pulseboard:${msg.from}`,
                  recipientAddress: `pulseboard:${account.username}`,
                  conversationLabel: msg.from,
                  rawBody: msg.text,
                  messageId: msg.messageId,
                  timestamp: msg.timestamp,
                  commandAuthorized: resolvedAccess.commandAuthorized,
                  deliver: async (payload) => {
                    const outboundText =
                      payload && typeof payload === "object" && "text" in payload
                        ? String((payload as { text?: string }).text ?? "")
                        : "";
                    if (!outboundText.trim()) return;
                    const tableMode = runtime.channel.text.resolveMarkdownTableMode({
                      cfg: ctx.cfg,
                      channel: "pulseboard",
                      accountId: account.accountId,
                    });
                    await clientHandle?.sendDm(
                      msg.from,
                      runtime.channel.text.convertMarkdownTables(outboundText, tableMode),
                    );
                  },
                  onRecordError: (err) => {
                    ctx.log?.error?.(
                      `[${account.accountId}] failed recording PulseBoard DM session: ${String(err)}`,
                    );
                  },
                  onDispatchError: (err, info) => {
                    ctx.log?.error?.(
                      `[${account.accountId}] PulseBoard DM ${info.kind} reply failed: ${String(err)}`,
                    );
                  },
                });
              } else if (msg.type === "board") {
                // Board (group) message: dispatch as a group peer.
                // commandAuthorized is left undefined — board messages do not
                // go through the DM access policy.
                await dispatchInboundDirectDmWithRuntime({
                  cfg: ctx.cfg,
                  runtime,
                  channel: "pulseboard",
                  channelLabel: "PulseBoard",
                  accountId: account.accountId,
                  peer: { kind: "group", id: msg.target },
                  senderId: msg.from,
                  senderAddress: `pulseboard:${msg.from}`,
                  recipientAddress: `pulseboard:${msg.target}`,
                  conversationLabel: `${msg.target} (${msg.from})`,
                  rawBody: msg.text,
                  messageId: msg.messageId,
                  timestamp: msg.timestamp,
                  deliver: async (payload) => {
                    const outboundText =
                      payload && typeof payload === "object" && "text" in payload
                        ? String((payload as { text?: string }).text ?? "")
                        : "";
                    if (!outboundText.trim()) return;
                    const tableMode = runtime.channel.text.resolveMarkdownTableMode({
                      cfg: ctx.cfg,
                      channel: "pulseboard",
                      accountId: account.accountId,
                    });
                    await clientHandle?.sendBoard(
                      msg.target,
                      runtime.channel.text.convertMarkdownTables(outboundText, tableMode),
                    );
                  },
                  onRecordError: (err) => {
                    ctx.log?.error?.(
                      `[${account.accountId}] failed recording PulseBoard board session: ${String(err)}`,
                    );
                  },
                  onDispatchError: (err, info) => {
                    ctx.log?.error?.(
                      `[${account.accountId}] PulseBoard board ${info.kind} reply failed: ${String(err)}`,
                    );
                  },
                });
              }
            },

            onConnect: () => {
              ctx.log?.info(
                `[${account.accountId}] PulseBoard connected to ${account.serverUrl}`,
              );
            },
            onDisconnect: () => {
              ctx.log?.info(
                `[${account.accountId}] PulseBoard disconnected from ${account.serverUrl}`,
              );
            },
            onError: (err) => {
              ctx.log?.error?.(
                `[${account.accountId}] PulseBoard connection error: ${err.message}`,
              );
            },
          });

          // Set the intermediate ref so onMessage callbacks can reach the client.
          clientHandle = client;
          activeClients.set(account.accountId, client);

          ctx.log?.info(
            `[${account.accountId}] PulseBoard provider started (subscribed to ${account.boards.length} board(s))`,
          );

          return {
            stop: () => {
              client.close();
              activeClients.delete(account.accountId);
              ctx.log?.info(`[${account.accountId}] PulseBoard provider stopped`);
            },
          };
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseBoardUser",
        message: "Your PulseBoard pairing request has been approved!",
        normalizeAllowEntry: (entry) => normalizePulseBoardAllowEntry(entry) ?? entry.trim(),
        notify: async ({ id, message }) => {
          const client = activeClients.get(DEFAULT_ACCOUNT_ID);
          if (client) {
            await client.sendDm(id, message);
          }
        },
      },
    },
    security: {
      resolveDmPolicy: resolvePulseBoardDmPolicy,
    },
    outbound: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
      sendText: async ({ cfg, to, text, accountId }) => {
        const core = getPulseBoardRuntime();
        const aid = accountId ?? DEFAULT_ACCOUNT_ID;
        const client = activeClients.get(aid);
        if (!client) {
          throw new Error(`PulseBoard client not running for account ${aid}`);
        }
        const tableMode = core.channel.text.resolveMarkdownTableMode({
          cfg,
          channel: "pulseboard",
          accountId: aid,
        });
        const message = core.channel.text.convertMarkdownTables(text ?? "", tableMode);
        if (isBoardTarget(to)) {
          const result = await client.sendBoard(to, message);
          return attachChannelToResult("pulseboard", {
            to,
            messageId: result.messageId,
          });
        }
        const result = await client.sendDm(to, message);
        return attachChannelToResult("pulseboard", {
          to,
          messageId: result.messageId,
        });
      },
    },
  },
);

