import { describe, expect, it, vi } from "vitest";
import {
  createPluginSetupWizardConfigure,
  createTestWizardPrompter,
  runSetupWizardConfigure,
  type WizardPrompter,
} from "../../../test/helpers/plugins/setup-wizard.js";
import type { OpenClawConfig } from "../runtime-api.js";
import { pulseBoardPlugin } from "./channel.js";
import { pulseBoardSetupWizard } from "./setup-surface.js";
import {
  TEST_API_TOKEN,
  TEST_BOARDS,
  TEST_SERVER_URL,
  TEST_USERNAME,
  createConfiguredPulseBoardCfg,
} from "./test-fixtures.js";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
} from "./types.js";

const pulseBoardConfigure = createPluginSetupWizardConfigure(pulseBoardPlugin);

function requireNormalizeTarget() {
  const normalize = pulseBoardPlugin.messaging?.normalizeTarget;
  if (!normalize) throw new Error("pulseboard messaging.normalizeTarget missing");
  return normalize;
}

function requireLooksLikeId() {
  const looksLikeId = pulseBoardPlugin.messaging?.targetResolver?.looksLikeId;
  if (!looksLikeId) throw new Error("pulseboard messaging.targetResolver.looksLikeId missing");
  return looksLikeId;
}

function requireResolveDmPolicy() {
  const resolveDmPolicy = pulseBoardPlugin.security?.resolveDmPolicy;
  if (!resolveDmPolicy) throw new Error("pulseboard security.resolveDmPolicy missing");
  return resolveDmPolicy;
}

function requirePairingNormalizer() {
  const normalize = pulseBoardPlugin.pairing?.normalizeAllowEntry;
  if (!normalize) throw new Error("pulseboard pairing.normalizeAllowEntry missing");
  return normalize;
}

describe("pulseBoardPlugin", () => {
  describe("meta", () => {
    it("has correct id", () => {
      expect(pulseBoardPlugin.id).toBe("pulseboard");
    });

    it("has required meta fields", () => {
      expect(pulseBoardPlugin.meta.label).toBe("PulseBoard");
      expect(pulseBoardPlugin.meta.docsPath).toBe("/channels/pulseboard");
      expect(pulseBoardPlugin.meta.blurb).toContain("bulletin board");
    });
  });

  describe("capabilities", () => {
    it("supports direct messages", () => {
      expect(pulseBoardPlugin.capabilities.chatTypes).toContain("direct");
    });

    it("supports group (board) messages", () => {
      expect(pulseBoardPlugin.capabilities.chatTypes).toContain("group");
    });

    it("does not support media (MVP)", () => {
      expect(pulseBoardPlugin.capabilities.media).toBe(false);
    });
  });

  describe("config adapter", () => {
    it("listAccountIds returns empty array for unconfigured", () => {
      const cfg = { channels: {} };
      expect(pulseBoardPlugin.config.listAccountIds(cfg)).toEqual([]);
    });

    it("listAccountIds returns default for fully configured", () => {
      const cfg = createConfiguredPulseBoardCfg();
      expect(pulseBoardPlugin.config.listAccountIds(cfg)).toContain("default");
    });

    it("listAccountIds returns empty when apiToken is missing", () => {
      const cfg = {
        channels: { pulseboard: { serverUrl: TEST_SERVER_URL, username: TEST_USERNAME } },
      };
      expect(pulseBoardPlugin.config.listAccountIds(cfg)).toEqual([]);
    });

    it("listAccountIds returns empty when serverUrl is missing", () => {
      const cfg = {
        channels: { pulseboard: { apiToken: TEST_API_TOKEN, username: TEST_USERNAME } },
      };
      expect(pulseBoardPlugin.config.listAccountIds(cfg)).toEqual([]);
    });

    it("listAccountIds returns empty when username is missing", () => {
      const cfg = {
        channels: { pulseboard: { apiToken: TEST_API_TOKEN, serverUrl: TEST_SERVER_URL } },
      };
      expect(pulseBoardPlugin.config.listAccountIds(cfg)).toEqual([]);
    });
  });

  describe("messaging", () => {
    it("recognizes #boardname as a valid target", () => {
      const looksLikeId = requireLooksLikeId();
      expect(looksLikeId("#general")).toBe(true);
      expect(looksLikeId("#dev-chat")).toBe(true);
    });

    it("recognizes plain username as a valid target", () => {
      const looksLikeId = requireLooksLikeId();
      expect(looksLikeId("alice")).toBe(true);
      expect(looksLikeId("user_123")).toBe(true);
    });

    it("recognizes @username as a valid target", () => {
      const looksLikeId = requireLooksLikeId();
      expect(looksLikeId("@alice")).toBe(true);
    });

    it("rejects empty and invalid input", () => {
      const looksLikeId = requireLooksLikeId();
      expect(looksLikeId("")).toBe(false);
      expect(looksLikeId("hello world")).toBe(false);
    });

    it("normalizeTarget strips leading @", () => {
      const normalize = requireNormalizeTarget();
      expect(normalize("@alice")).toBe("alice");
      expect(normalize("  @alice  ")).toBe("alice");
    });

    it("normalizeTarget preserves # for board targets", () => {
      const normalize = requireNormalizeTarget();
      expect(normalize("#general")).toBe("#general");
      expect(normalize("  #dev  ")).toBe("#dev");
    });

    it("normalizeTarget passes plain usernames through unchanged", () => {
      const normalize = requireNormalizeTarget();
      expect(normalize("alice")).toBe("alice");
    });

    it("normalizeTarget returns undefined for empty input", () => {
      const normalize = requireNormalizeTarget();
      expect(normalize("")).toBeUndefined();
      expect(normalize("   ")).toBeUndefined();
    });
  });

  describe("outbound", () => {
    it("has direct delivery mode", () => {
      expect(pulseBoardPlugin.outbound?.deliveryMode).toBe("direct");
    });

    it("has 4000-character text chunk limit", () => {
      expect(pulseBoardPlugin.outbound?.textChunkLimit).toBe(4000);
    });
  });

  describe("pairing", () => {
    it("has the expected id label", () => {
      expect(pulseBoardPlugin.pairing?.idLabel).toBe("pulseBoardUser");
    });

    it("normalizes @-prefixed usernames in allow entries", () => {
      const normalize = requirePairingNormalizer();
      expect(normalize("@alice")).toBe("alice");
      expect(normalize("  @bob  ")).toBe("bob");
    });

    it("preserves plain usernames in allow entries", () => {
      const normalize = requirePairingNormalizer();
      expect(normalize("alice")).toBe("alice");
    });
  });

  describe("security", () => {
    it("has a resolveDmPolicy adapter", () => {
      expect(pulseBoardPlugin.security?.resolveDmPolicy).toBeDefined();
    });

    it("normalizes allowlist entries through the dm policy adapter", () => {
      const resolveDmPolicy = requireResolveDmPolicy();
      const cfg = createConfiguredPulseBoardCfg({
        dmPolicy: "allowlist",
        allowFrom: ["@alice", "  bob  "],
      });
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      const result = resolveDmPolicy({ cfg, account });
      if (!result) throw new Error("pulseboard resolveDmPolicy returned null");
      expect(result.policy).toBe("allowlist");
      expect(result.normalizeEntry?.("@alice")).toBe("alice");
      expect(result.normalizeEntry?.("  @carol  ")).toBe("carol");
    });
  });

  describe("status", () => {
    it("has default runtime with expected shape", () => {
      expect(pulseBoardPlugin.status?.defaultRuntime).toEqual({
        accountId: "default",
        running: false,
        lastStartAt: null,
        lastStopAt: null,
        lastError: null,
      });
    });
  });

  describe("setup wizard", () => {
    it("has apiToken credential", () => {
      expect(pulseBoardSetupWizard.credentials?.[0]?.inputKey).toBe("apiToken");
    });

    it("has serverUrl, username, and boards text inputs", () => {
      const inputKeys = pulseBoardSetupWizard.textInputs?.map((i) => i.inputKey) ?? [];
      expect(inputKeys).toContain("serverUrl");
      expect(inputKeys).toContain("username");
      expect(inputKeys).toContain("boards");
    });

    it("has a dm policy", () => {
      expect(pulseBoardSetupWizard.dmPolicy).toBeDefined();
    });
  });
});

describe("pulseboard setup wizard (integration)", () => {
  it("configures apiToken, serverUrl, username, and boards", async () => {
    const prompter = createTestWizardPrompter({
      text: vi.fn(async ({ message }: { message: string }) => {
        if (message === "PulseBoard API token") return TEST_API_TOKEN;
        if (message === "PulseBoard server URL (ws:// or wss://)") return TEST_SERVER_URL;
        if (message === "Your PulseBoard username") return TEST_USERNAME;
        if (message === "Boards to subscribe to (comma-separated, optional)") {
          return TEST_BOARDS.join(", ");
        }
        throw new Error(`Unexpected wizard prompt: ${message}`);
      }) as WizardPrompter["text"],
    });

    const result = await runSetupWizardConfigure({
      configure: pulseBoardConfigure,
      cfg: {} as OpenClawConfig,
      prompter,
      options: {},
    });

    expect(result.accountId).toBe("default");
    const pb = (result.cfg as Record<string, unknown>).channels as
      | Record<string, unknown>
      | undefined;
    const pbSection = pb?.pulseboard as Record<string, unknown> | undefined;
    expect(pbSection?.enabled).toBe(true);
    expect(pbSection?.apiToken).toBe(TEST_API_TOKEN);
    expect(pbSection?.serverUrl).toBe(TEST_SERVER_URL);
    expect(pbSection?.username).toBe(TEST_USERNAME);
    expect(pbSection?.boards).toEqual(TEST_BOARDS);
  });
});

describe("pulseboard account helpers", () => {
  describe("listPulseBoardAccountIds", () => {
    it("returns empty array when not configured", () => {
      expect(listPulseBoardAccountIds({ channels: {} })).toEqual([]);
    });

    it("returns empty array when only partially configured (missing username)", () => {
      const cfg = {
        channels: { pulseboard: { apiToken: TEST_API_TOKEN, serverUrl: TEST_SERVER_URL } },
      };
      expect(listPulseBoardAccountIds(cfg)).toEqual([]);
    });

    it("returns default when fully configured", () => {
      const cfg = createConfiguredPulseBoardCfg();
      expect(listPulseBoardAccountIds(cfg)).toEqual(["default"]);
    });

    it("respects a configured defaultAccount", () => {
      const cfg = createConfiguredPulseBoardCfg({ defaultAccount: "work" });
      expect(listPulseBoardAccountIds(cfg)).toEqual(["work"]);
    });
  });

  describe("resolveDefaultPulseBoardAccountId", () => {
    it("returns default when configured", () => {
      const cfg = createConfiguredPulseBoardCfg();
      expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("default");
    });

    it("returns default when not configured", () => {
      expect(resolveDefaultPulseBoardAccountId({ channels: {} })).toBe("default");
    });

    it("prefers a configured defaultAccount when present", () => {
      const cfg = createConfiguredPulseBoardCfg({ defaultAccount: "work" });
      expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("work");
    });
  });

  describe("resolvePulseBoardAccount", () => {
    it("resolves a configured account", () => {
      const cfg = createConfiguredPulseBoardCfg({
        boards: TEST_BOARDS,
        dmPolicy: "pairing" as const,
      });
      const account = resolvePulseBoardAccount({ cfg });
      expect(account.accountId).toBe("default");
      expect(account.enabled).toBe(true);
      expect(account.configured).toBe(true);
      expect(account.apiToken).toBe(TEST_API_TOKEN);
      expect(account.serverUrl).toBe(TEST_SERVER_URL);
      expect(account.username).toBe(TEST_USERNAME);
      expect(account.boards).toEqual(TEST_BOARDS);
    });

    it("resolves an unconfigured account with safe defaults", () => {
      const account = resolvePulseBoardAccount({ cfg: { channels: {} } });
      expect(account.configured).toBe(false);
      expect(account.apiToken).toBe("");
      expect(account.serverUrl).toBe("");
      expect(account.username).toBe("");
      expect(account.boards).toEqual([]);
    });

    it("handles a disabled channel", () => {
      const cfg = createConfiguredPulseBoardCfg({ enabled: false });
      const account = resolvePulseBoardAccount({ cfg });
      expect(account.enabled).toBe(false);
      expect(account.configured).toBe(true);
    });

    it("does not treat an unresolved SecretRef apiToken as configured", () => {
      const secretRef = {
        source: "env" as const,
        provider: "default",
        id: "PULSEBOARD_API_TOKEN",
      };
      const cfg = {
        channels: {
          pulseboard: {
            apiToken: secretRef,
            serverUrl: TEST_SERVER_URL,
            username: TEST_USERNAME,
          },
        },
      };
      const account = resolvePulseBoardAccount({ cfg });
      expect(account.configured).toBe(false);
      expect(account.apiToken).toBe("");
      expect(account.config.apiToken).toEqual(secretRef);
    });

    it("preserves all config options", () => {
      const cfg = createConfiguredPulseBoardCfg({
        name: "Bot",
        enabled: true,
        boards: TEST_BOARDS,
        dmPolicy: "allowlist" as const,
        allowFrom: ["alice", "bob"],
      });
      const account = resolvePulseBoardAccount({ cfg });
      expect(account.config).toEqual({
        apiToken: TEST_API_TOKEN,
        serverUrl: TEST_SERVER_URL,
        username: TEST_USERNAME,
        name: "Bot",
        enabled: true,
        boards: TEST_BOARDS,
        dmPolicy: "allowlist",
        allowFrom: ["alice", "bob"],
      });
    });
  });

  describe("setup wizard credential inspection", () => {
    it("keeps an unresolved SecretRef apiToken visible without marking the account configured", () => {
      const secretRef = {
        source: "env" as const,
        provider: "default",
        id: "PULSEBOARD_API_TOKEN",
      };
      const cfg = {
        channels: {
          pulseboard: {
            apiToken: secretRef,
            serverUrl: TEST_SERVER_URL,
            username: TEST_USERNAME,
          },
        },
      };
      const credential = pulseBoardSetupWizard.credentials?.[0];
      if (!credential?.inspect) {
        throw new Error("pulseboard setup credential inspect missing");
      }
      expect(credential.inspect({ cfg, accountId: "default" })).toEqual({
        accountConfigured: false,
        hasConfiguredValue: true,
        resolvedValue: undefined,
        envValue: undefined,
      });
    });
  });
});

